import React, { useEffect, useState } from 'react';
import axios from 'axios';

const TYPE_META = {
  general: { icon: 'ℹ️', color: '#3b82f6', bg: '#eff6ff' },
  schedule: { icon: '📅', color: '#8b5cf6', bg: '#f5f3ff' },
  payment_due: { icon: '💳', color: '#ef4444', bg: '#fef2f2' },
  payment_received: { icon: '✅', color: '#10b981', bg: '#f0fdf4' },
  overdue: { icon: '⚠️', color: '#f59e0b', bg: '#fffbeb' },
};

export default function StudentNotifications() {
  const [notifications, setNotifications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  const load = () => {
    axios.get('/notifications').then(r => setNotifications(r.data)).catch(console.error).finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  const markRead = async (id) => {
    await axios.put(`/notifications/${id}/read`);
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const markAllRead = async () => {
    await axios.put('/notifications/read-all');
    setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
  };

  const filtered = filter === 'all' ? notifications
    : filter === 'unread' ? notifications.filter(n => !n.isRead)
    : notifications.filter(n => n.isRead);

  const unread = notifications.filter(n => !n.isRead).length;

  const timeAgo = (date) => {
    const diff = Date.now() - new Date(date);
    const m = Math.floor(diff / 60000);
    if (m < 1) return 'just now';
    if (m < 60) return `${m}m ago`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}h ago`;
    return `${Math.floor(h / 24)}d ago`;
  };

  if (loading) return <div className="loading-screen" style={{ height: 300 }}><div className="spinner" /></div>;

  return (
    <div>
      <div className="notif-page-header">
        <div>
          <h3 style={{ fontSize: 18, fontWeight: 800 }}>Notifications</h3>
          <p style={{ fontSize: 13, color: 'var(--text-muted)' }}>{unread > 0 ? `${unread} unread notification${unread > 1 ? 's' : ''}` : 'You\'re all caught up!'}</p>
        </div>
        {unread > 0 && <button className="btn btn-outline btn-sm" onClick={markAllRead}>✓ Mark all read</button>}
      </div>

      <div className="toolbar" style={{ marginBottom: 20 }}>
        {['all', 'unread', 'read'].map(f => (
          <button key={f} className={`btn ${filter === f ? 'btn-primary' : 'btn-outline'} btn-sm`} onClick={() => setFilter(f)} style={{ textTransform: 'capitalize' }}>
            {f} ({f === 'all' ? notifications.length : f === 'unread' ? unread : notifications.length - unread})
          </button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <div className="card">
          <div className="empty-state">
            <span className="icon">🔔</span>
            <h3>No notifications</h3>
            <p>Payment reminders and updates will appear here</p>
          </div>
        </div>
      ) : (
        <div className="notif-feed">
          {filtered.map(n => {
            const meta = TYPE_META[n.type] || TYPE_META.info;
            return (
              <div key={n.id} className={`notif-feed-item ${!n.isRead ? 'unread' : ''}`} onClick={() => !n.isRead && markRead(n.id)}>
                <div className="notif-feed-icon" style={{ background: meta.bg, color: meta.color }}>{meta.icon}</div>
                <div className="notif-feed-body">
                  <div className="notif-feed-top">
                    <strong>{n.title}</strong>
                    <span className="notif-feed-time">{timeAgo(n.createdAt)}</span>
                  </div>
                  <p>{n.message}</p>
                  {!n.isRead && <span className="unread-dot">New</span>}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
